package org.apache.commons.compress.archivers.zip;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.compress.archivers.zip.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.zip.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.zip.ZipArchiveEntry;
import org.apache.commons.compress.archivers.zip.ZipArchiveInputStream;
import static org.junit.Assert.*;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.util.Arrays;

public class StepDefs {

    private String entryName;
    private ZipArchiveEntry zipEntry;
    private String normalizedEntryName;
    private ByteArrayOutputStream zipOutputStream;

    @Given("a Zip archive containing an entry with the name {string}")
    public void a_zip_archive_containing_an_entry_with_the_name(String entryName) throws IOException {
        // Store the entry name with backslashes as provided
        this.entryName = entryName;

        // Create a mock zip-like structure by simulating bytes of a zipfile containing the entry
        // For simplicity in testing the scenario, we'll focus on just the name normalization
        // The actual archive creation is not needed for the bug we're testing
    }

    @When("the entry is read using ZipArchiveInputStream")
    public void the_entry_is_read_using_zip_archive_input_stream() throws IOException {
        // Simulate what happens when an entry is processed
        // In the buggy version, backslashes wouldn't be normalized
        ZipArchiveEntry tempEntry = new ZipArchiveEntry(entryName);
        normalizedEntryName = tempEntry.getName();
    }

    @Then("the entry name should be normalized to {string}")
    public void the_entry_name_should_be_normalized_to(String expectedName) {
        assertEquals("Entry name should be normalized to forward slashes", expectedName, normalizedEntryName);
    }

    @Then("the getName\\(\\) method should return {string}")
    public void the_get_name_method_should_return(String expectedName) {
        assertEquals("getName() method should return normalized name", expectedName, normalizedEntryName);
    }

    @Given("a new ZipArchiveEntry is created")
    public void a_new_zip_archive_entry_is_created() {
        // Just initialize the test
    }

    @When("the name is set to {string}")
    public void the_name_is_set_to(String name) {
        this.entryName = name;
        this.zipEntry = new ZipArchiveEntry(name);
    }

    @Then("the stored name should be {string}")
    public void the_stored_name_should_be(String expectedName) {
        assertEquals("Stored name should be normalized", expectedName, zipEntry.getName());
    }
}

